      <div ref="chartRef" class="chart" />
      <div class="analysis"><div><b>78%</b><span>目标范围内时间 TIR</span></div><div><b>4%</b><span>低血糖占比</span></div><div><b>18%</b><span>高血糖占比</span></div><div><b>1.2</b><span>波动系数 MAGE</span></div></div>
    </section>
    <section class="records-grid">
