<script setup>
import { nextTick, onBeforeUnmount, onMounted, ref } from 'vue'
import { useRouter } from 'vue-router'
import * as echarts from 'echarts'
import { ElMessage } from 'element-plus'
import { Download, Plus, WarningFilled, Food, Bicycle, TrendCharts, ArrowRight, Watch, Opportunity, Camera } from '@element-plus/icons-vue'
import { listGlucose } from '../api'
const router=useRouter(), range=ref('week'), records=ref([]), chartRef=ref(), recordDialog=ref(false); let chart
