async function load(){const days={day:1,week:7,month:30}[range.value];try{records.value=await listGlucose({from:new Date(Date.now()-days*864e5).toISOString().slice(0,19)})||[]}catch{records.value=[]}await nextTick();render()}
function render(){if(!chartRef.value)return;chart ||= echarts.init(chartRef.value);const fallback=[5.6,6.0,6.4,7.5,6.7,5.9,6.3,8.2,7.1,6.2,5.8,6.1];const vals=records.value.length?records.value.map(r=>Number(r.valueMmol)):fallback;chart.setOption({tooltip:{trigger:'axis'},grid:{left:45,right:20,top:30,bottom:35},xAxis:{type:'category',boundaryGap:false,data:vals.map((_,i)=>`${i+1}`),axisLine:{lineStyle:{color:'#dce9e4'}},axisTick:{show:false},axisLabel:{color:'#82968f'}},yAxis:{type:'value',min:2,max:12,splitLine:{lineStyle:{color:'#edf3f0'}},axisLabel:{color:'#82968f'}},series:[{type:'line',smooth:true,data:vals,symbolSize:7,itemStyle:{color:'#216b5d'},lineStyle:{color:'#35a889',width:3},areaStyle:{color:new echarts.graphic.LinearGradient(0,0,0,1,[{offset:0,color:'rgba(53,168,137,.24)'},{offset:1,color:'rgba(53,168,137,0)'}])},markArea:{silent:true,itemStyle:{color:'rgba(121,209,182,.12)'},data:[[{yAxis:3.9},{yAxis:7.8}]]},markLine:{silent:true,symbol:'none',data:[{yAxis:3.9,lineStyle:{color:'#e6a23c'}},{yAxis:7.8,lineStyle:{color:'#e35d65'}}]}}]})}
function openRoute(path){recordDialog.value=false;router.push(path)}
function exportCsv(){const rows=['时间,血糖(mmol/L)',...records.value.map(r=>`${r.measuredAt},${r.valueMmol}`)];const blob=new Blob(['\ufeff'+rows.join('\n')],{type:'text/csv;charset=utf-8'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`health-data-${new Date().toISOString().slice(0,10)}.csv`;a.click();URL.revokeObjectURL(a.href);ElMessage.success('数据已导出')}
function resize(){chart?.resize()}onMounted(()=>{load();window.addEventListener('resize',resize)});onBeforeUnmount(()=>{window.removeEventListener('resize',resize);chart?.dispose()})
</script>
